import{_ as a,o,c as n,a3 as r}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"53. Meal Allowance","description":"","frontmatter":{"title":"53. Meal Allowance","eba":"Doctors in Training 2022-2026","topics":["hours","shift-work","allowances","meal"]},"headers":[],"relativePath":"ebas/doctors-in-training/allowances/53-meal-allowance.md","filePath":"ebas/doctors-in-training/allowances/53-meal-allowance.md"}'),t={name:"ebas/doctors-in-training/allowances/53-meal-allowance.md"};function l(s,e,i,c,d,p){return o(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="_53-meal-allowance" tabindex="-1">53. Meal Allowance <a class="header-anchor" href="#_53-meal-allowance" aria-label="Permalink to &quot;53. Meal Allowance&quot;">​</a></h1><p><strong>53.1</strong> Where a Doctor works in excess of 11 hours in any 24-hour period, an adequate meal must be provided or a Meal Allowance (in excess of 11 hours) as detailed in <a href="/eba/ebas/doctors-in-training/appendices/2-doctors-in-training-remuneration-allowances-and-deductions.html">Appendix 2</a>, Table 2.3 must be paid in lieu; or</p><p><strong>(a)</strong> where a Doctor works in excess of 16 hours in any 24 hour period – two adequate meals must be provided or the Meal Allowance described in subclause 53.1 above and a further Meal Allowance (in excess of 16 hours) as detailed in <a href="/eba/ebas/doctors-in-training/appendices/2-doctors-in-training-remuneration-allowances-and-deductions.html">Appendix 2</a>, Table 2.3 must be paid; and</p><p><strong>(b)</strong> for each six hour period the Doctor works in excess of 16 hours until the shift ends, a further meal must be provided or a further Meal Allowance as detailed in</p><p>Plain language terms: meal money.</p>',5)])])}const m=a(t,[["render",l]]);export{h as __pageData,m as default};
